import{_ as a,H as t,f as r,i as o}from"./chunks/framework.nN4pLK1d.js";const p=JSON.parse('{"title":"Function: applyTheme()","description":"","frontmatter":{},"headers":[],"relativePath":"api/rcml/src/functions/applyTheme.md","filePath":"api/rcml/src/functions/applyTheme.md"}'),c={name:"api/rcml/src/functions/applyTheme.md"};function l(h,e,m,s,i,n){return t(),r("div",null,[...e[0]||(e[0]=[o('<p><a href="./../../../"><strong>Rule.io SDK</strong></a></p><hr><p><a href="./../../../">Rule.io SDK</a> / <a href="./../">rcml/src</a> / applyTheme</p><h1>Function: applyTheme()</h1><blockquote><p><strong>applyTheme</strong>(<code>doc</code>, <code>theme</code>): <a href="./../interfaces/RcmlDocument.html"><code>RcmlDocument</code></a></p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/026baf8f0684b8a015362370e35fbcd4c5ec8938/packages/rcml/src/email/apply-theme.ts#L78" target="_blank" rel="noreferrer">rcml/src/email/apply-theme.ts:78</a></p><p>Apply a theme or a partial patch to an RCML document. The input doc is not mutated; a new <a href="./../interfaces/RcmlDocument.html">RcmlDocument</a> is returned.</p><p>Every bucket uses <strong>overlay</strong> semantics: for each entry the caller provides, the matching rcml node is upserted (updated if present, created if missing). Entries the caller does <em>not</em> mention are left alone. This means:</p><ul><li>Pass a full <a href="./../interfaces/EmailTheme.html">EmailTheme</a> → every bucket&#39;s every sub-slot is present, so every theme-controlled node is upserted. The doc ends up matching the theme, but any orphan custom nodes that aren&#39;t part of the theme&#39;s vocabulary survive.</li><li>Pass a partial <a href="./../interfaces/EmailThemePatch.html">EmailThemePatch</a> (e.g. <code>{ colors: [{ type: Primary, hex: &#39;#F00&#39; }] }</code>) → only <code>rc-button</code>&#39;s background-color is touched. <code>rc-body</code>, <code>rc-section</code>, the <code>rcml-brand-color</code> class, <code>rc-social</code>, <code>rc-font</code> etc. are untouched.</li><li>Pass an empty bucket (e.g. <code>{ colors: [] }</code>) → no-op for that bucket. <code>applyTheme</code> never removes nodes; there&#39;s no explicit &quot;clear&quot; verb.</li></ul><p>Works uniformly on:</p><ul><li>Docs with no theme yet (missing head nodes get created).</li><li>Docs with the default theme applied (node identity preserved; <code>id</code>s kept).</li><li>Docs with a different custom theme (same upsert-only behaviour).</li></ul><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><h3 id="doc" tabindex="-1">doc <a class="header-anchor" href="#doc" aria-label="Permalink to &quot;doc&quot;">​</a></h3><p><a href="./../interfaces/RcmlDocument.html"><code>RcmlDocument</code></a></p><p>The document to theme. Not mutated.</p><h3 id="theme" tabindex="-1">theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;theme&quot;">​</a></h3><p><a href="./../interfaces/EmailTheme.html"><code>EmailTheme</code></a> | <a href="./../interfaces/EmailThemePatch.html"><code>EmailThemePatch</code></a></p><p>Either a full <a href="./../interfaces/EmailTheme.html">EmailTheme</a> or a partial <a href="./../interfaces/EmailThemePatch.html">EmailThemePatch</a>.</p><h2 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h2><p><a href="./../interfaces/RcmlDocument.html"><code>RcmlDocument</code></a></p><p>A new <a href="./../interfaces/RcmlDocument.html">RcmlDocument</a> with the theme applied.</p><h2 id="throws" tabindex="-1">Throws <a class="header-anchor" href="#throws" aria-label="Permalink to &quot;Throws&quot;">​</a></h2><p><a href="./../classes/EmailThemeApplyError.html">EmailThemeApplyError</a> when a URL (logo src, social href, font href) fails safety validation.</p>',23)])])}const u=a(c,[["render",l]]);export